import{_ as i,c as o,o as n,a5 as a,j as e}from"./chunks/framework.Dtwt352Q.js";const m=JSON.parse('{"title":"v1.1.24: Desktop Transformation, Unified Search","description":"","frontmatter":{},"headers":[],"relativePath":"en/changelog/v1.1.24.md","filePath":"en/changelog/v1.1.24.md","lastUpdated":1772014034000}'),r={name:"en/changelog/v1.1.24.md"};function s(l,t,d,h,c,p){return n(),o("div",null,[...t[0]||(t[0]=[a('<h1 id="v1-1-24-desktop-transformation-unified-search" tabindex="-1">v1.1.24: Desktop Transformation, Unified Search <a class="header-anchor" href="#v1-1-24-desktop-transformation-unified-search" aria-label="Permalink to “v1.1.24: Desktop Transformation, Unified Search”">​</a></h1><p><strong>Release Date</strong>: January 16, 2026</p><hr><h2 id="one-line-summary" tabindex="-1">One-Line Summary <a class="header-anchor" href="#one-line-summary" aria-label="Permalink to “One-Line Summary”">​</a></h2><p>This update brings a brand new desktop layout, supports unified search for files and commands, and allows customizing project and session titles for easier management.</p><hr><h2 id="new-feature-brand-new-desktop-layout-and-unified-search" tabindex="-1">New Feature: Brand New Desktop Layout and Unified Search <a class="header-anchor" href="#new-feature-brand-new-desktop-layout-and-unified-search" aria-label="Permalink to “New Feature: Brand New Desktop Layout and Unified Search”">​</a></h2><h3 id="what-s-updated" tabindex="-1">What&#39;s Updated? <a class="header-anchor" href="#what-s-updated" aria-label="Permalink to “What&#39;s Updated?”">​</a></h3><p>Desktop App has undergone a visual upgrade! Not only is the interface cleaner, but most importantly it brings <strong>Unified Search Bar</strong>.</p><h3 id="what-is-unified-search" tabindex="-1">What Is Unified Search? <a class="header-anchor" href="#what-is-unified-search" aria-label="Permalink to “What Is Unified Search?”">​</a></h3><p>Previously you needed to find files and commands separately, now you don&#39;t. The top search bar is now all-powerful:</p><ul><li>Search <strong>files</strong>: Quickly open code files in project</li><li>Search <strong>commands</strong>: Directly run OpenCode slash commands (like <code>/reset</code>, <code>/search</code>, etc.)</li></ul><h3 id="how-to-use" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use" aria-label="Permalink to “How to Use?”">​</a></h3><ol><li>Open desktop app</li><li>Click the top search bar (or notice if there&#39;s a shortcut hint, usually <code>Cmd+K</code> or <code>Ctrl+K</code>)</li><li>Enter the file name or command you want to find, jump directly</li></ol><hr><h2 id="new-feature-custom-project-and-session-titles" tabindex="-1">New Feature: Custom Project and Session Titles <a class="header-anchor" href="#new-feature-custom-project-and-session-titles" aria-label="Permalink to “New Feature: Custom Project and Session Titles”">​</a></h2><h3 id="previous-issue" tabindex="-1">Previous Issue <a class="header-anchor" href="#previous-issue" aria-label="Permalink to “Previous Issue”">​</a></h3><p>OpenCode automatically generates session titles based on conversation content, sometimes AI-chosen names aren&#39;t intuitive enough, or you want to give a project a more memorable name.</p><h3 id="current-behavior" tabindex="-1">Current Behavior <a class="header-anchor" href="#current-behavior" aria-label="Permalink to “Current Behavior”">​</a></h3><p>You can finally rename them yourself!</p><h3 id="how-to-use-1" tabindex="-1">How to Use? <a class="header-anchor" href="#how-to-use-1" aria-label="Permalink to “How to Use?”">​</a></h3><ol><li><strong>Rename session</strong>: Find the session you want to rename in sidebar, click the edit icon (usually pencil shape) next to the title, enter new name and press enter</li><li><strong>Rename project</strong>: Same way, you can manage your project list and keep them organized</li></ol><hr><h2 id="new-feature-carbonfox-theme" tabindex="-1">New Feature: Carbonfox Theme <a class="header-anchor" href="#new-feature-carbonfox-theme" aria-label="Permalink to “New Feature: Carbonfox Theme”">​</a></h2><h3 id="what-is-this" tabindex="-1">What Is This? <a class="header-anchor" href="#what-is-this" aria-label="Permalink to “What Is This?”">​</a></h3><p>Added a dark theme called <strong>Carbonfox</strong>, designed for developers who like minimalist, high-contrast styles.</p><h3 id="how-to-switch" tabindex="-1">How to Switch? <a class="header-anchor" href="#how-to-switch" aria-label="Permalink to “How to Switch?”">​</a></h3><p>In terminal or app enter:</p>',28),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"/theme select")])],-1),a('<p>Then select <code>Carbonfox</code> to experience.</p><hr><h2 id="improvement-mcp-oauth-configuration" tabindex="-1">Improvement: MCP OAuth Configuration <a class="header-anchor" href="#improvement-mcp-oauth-configuration" aria-label="Permalink to “Improvement: MCP OAuth Configuration”">​</a></h2><h3 id="what-is-this-1" tabindex="-1">What Is This? <a class="header-anchor" href="#what-is-this-1" aria-label="Permalink to “What Is This?”">​</a></h3><p>For advanced users using Model Context Protocol (MCP), OAuth redirect URI configuration is now supported. This means you can more conveniently connect to MCP servers requiring complex authentication.</p><hr><h2 id="should-you-upgrade" tabindex="-1">Should You Upgrade? <a class="header-anchor" href="#should-you-upgrade" aria-label="Permalink to “Should You Upgrade?”">​</a></h2><table tabindex="0"><thead><tr><th>Situation</th><th>Recommendation</th></tr></thead><tbody><tr><td>Using desktop app</td><td>✅ <strong>Strongly recommended upgrade</strong>, new layout and search are great</td></tr><tr><td>Frequently need to manage multiple sessions</td><td>✅ Upgrade, rename feature is practical</td></tr><tr><td>Only using terminal CLI</td><td>Can upgrade, some TUI small optimizations</td></tr></tbody></table><p><strong>Upgrade Command</strong>:</p>',9),e("div",{class:"language-bash"},[e("button",{title:"Copy Code",class:"copy"}),e("span",{class:"lang"},"bash"),e("pre",null,[e("code",{"v-pre":""},"opencode upgrade")])],-1),a('<hr><h2 id="technical-details-skippable" tabindex="-1">Technical Details (Skippable) <a class="header-anchor" href="#technical-details-skippable" aria-label="Permalink to “Technical Details (Skippable)”">​</a></h2><details><summary>Click to expand full changelog</summary><p><strong>Core</strong></p><ul><li>Upgrade OpenTUI to v0.1.74, fix kitty keyboard compatibility under tmux</li><li>Ensure tool attachments aren&#39;t sent as user messages</li><li>Use dynamic import for session event in config.ts to avoid circular dependencies</li><li>Fix broken URLs in documentation</li><li>Fix GPT model itemId stripping logic</li><li>Add OAuth redirect URI configuration for MCP servers</li><li>Adjust web search tool, emphasize current date and clarify no longer 2024</li><li>Optimize documentation about question tool usage</li><li>Set OpenCode as User-Agent for most reasoning requests</li><li>Show auth URL when browser can&#39;t be opened in remote session</li><li>Strip item IDs in more scenarios</li><li>Fix accidental main model/agent change when calling subtasks</li><li>Fix default agent selection in ACP and headless mode</li><li>Add LiteLLM proxy provider option for improved compatibility</li></ul><p><strong>TUI</strong></p><ul><li>Show version number in session header and /status dialog</li><li>Fix theme count prompt message in TUI</li><li>Dim question option prefix style in terminal UI</li><li>Add Tab key navigation support for questions in terminal interface</li><li>Add Carbonfox theme</li></ul><p><strong>Desktop</strong></p><ul><li>Add ability to edit project and session titles</li><li>Automatically open workspace when navigating to session within workspace</li><li>Fix workspace not expanding</li><li>Fix page jumping when expanding workspace</li><li>Truncate long workspace names on hover</li><li>Fix new session handling in app</li><li>Center dialogs to page instead of session area</li><li>Persist workspace order and collapsed state</li><li>Add unified search for commands and files</li><li>Add skeleton loading for session list</li><li>Fix project avatar corner radius</li></ul></details><hr><p><a href="./">← Back to Changelog</a></p>',5)])])}const g=i(r,[["render",s]]);export{m as __pageData,g as default};
